/**  Animated background gradient  */
const BackgroundLayer = memo(function BackgroundLayer() {
  return (
    <div className="absolute inset-0 overflow-hidden">
      {/* Base dark gradient */}
      <div className="absolute inset-0 bg-[radial-gradient(ellipse_80%_60%_at_50%_40%,rgba(16,185,129,0.07),transparent_70%)]" />
      <div className="absolute inset-0 bg-[radial-gradient(ellipse_60%_50%_at_50%_50%,rgba(45,212,191,0.04),transparent_60%)]" />

      {/* Subtle grid */}
      <div
        className="absolute inset-0 opacity-[0.03]"
        style={{
          backgroundImage:
            'linear-gradient(rgba(255,255,255,0.06) 1px, transparent 1px), linear-gradient(90deg, rgba(255,255,255,0.06) 1px, transparent 1px)',
          backgroundSize: '60px 60px',
        }}
      />

      {/* Animated scan line */}
      <motion.div
        className="absolute left-0 right-0 h-px"
        style={{
          background: 'linear-gradient(90deg, transparent, rgba(45,212,191,0.15), transparent)',
        }}
        animate={{ top: ['0%', '100%'] }}
        transition={{ duration: 4, repeat: Infinity, ease: 'linear' }}
      />
    </div>
  );
});

/**  Expanding radar rings from center core  */
const RadarRings = memo(function RadarRings() {
  return (
    <>
      {[0, 1, 2].map((i) => (
        <motion.div
          key={i}
          className="absolute rounded-full border"
          style={{
            width: 260 + i * 80,
            height: 260 + i * 80,
            left: '50%',
            top: '50%',
            x: '-50%',
            y: '-50%',
            borderColor: `rgba(45, 212, 191, ${0.08 - i * 0.02})`,
          }}
          initial={{ scale: 0.6, opacity: 0 }}
          animate={{ scale: 1, opacity: 1 }}
          transition={{ delay: 0.3 + i * 0.2, duration: 1, ease: 'easeOut' }}
        />
      ))}

      {/* Pulsing radar sweep rings */}
      {[0, 1].map((i) => (
        <motion.div
          key={`pulse-${i}`}
          className="absolute rounded-full"
          style={{
            width: 100,
            height: 100,
            left: '50%',
            top: '50%',
            x: '-50%',
            y: '-50%',
            border: '1px solid rgba(45, 212, 191, 0.25)',
          }}
          animate={{
            scale: [1, 4],
            opacity: [0.4, 0],
          }}
          transition={{
            duration: 3,
            repeat: Infinity,
            delay: i * 1.5,
            ease: 'easeOut',
          }}
        />
      ))}
    </>
  );
});

